export async function script(input) {
  const asList = (value) => Array.isArray(value) ? value.map((item) => String(item || '').trim()).filter(Boolean) : [];
  const normalizeUrl = (value) => {
    const text = String(value || '').trim();
    if (!text) return '';
    try {
      const parsed = new URL(text);
      if (!['http:', 'https:'].includes(parsed.protocol)) return '';
      parsed.hash = '';
      return parsed.toString();
    } catch {
      return '';
    }
  };
  const headerValue = (headers, name) => {
    if (!headers || typeof headers !== 'object') return null;
    const expected = name.toLowerCase();
    for (const [key, value] of Object.entries(headers)) {
      if (String(key).toLowerCase() === expected) return value == null ? null : String(value);
    }
    return null;
  };
  const httpResponses = Array.isArray(input.httpResponses) ? input.httpResponses : [];
  const responseUrls = httpResponses.map((item) => item?.url || item?.finalUrl || item?.input).map(normalizeUrl).filter(Boolean);
  const requestedUrls = asList(input.liveUrls).map(normalizeUrl).filter(Boolean);
  const targets = Array.from(new Set([...responseUrls, ...requestedUrls])).slice(0, 25);
  const suppliedOrigins = asList(input.testOrigins).filter((origin) => /^https?:\/\//i.test(origin));
  const origins = (suppliedOrigins.length > 0 ? suppliedOrigins : ['https://attacker.example', 'https://evil.invalid']).slice(0, 5);
  const probeErrors = [];
  let probeResults = Array.isArray(input.corsProbeResults) ? input.corsProbeResults : [];
  async function fetchProbe(url, origin, method) {
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), 10000);
    try {
      const headers = { Origin: origin, Accept: '*/*', 'User-Agent': 'SentrisFlow-CORS-Audit/1.0' };
      if (method === 'OPTIONS') {
        headers['Access-Control-Request-Method'] = 'POST';
        headers['Access-Control-Request-Headers'] = 'authorization, content-type';
      }
      const response = await fetch(url, { method, headers, redirect: 'manual', signal: controller.signal });
      return {
        url,
        origin,
        method,
        status: response.status,
        accessControlAllowOrigin: response.headers.get('access-control-allow-origin'),
        accessControlAllowCredentials: response.headers.get('access-control-allow-credentials'),
        accessControlAllowMethods: response.headers.get('access-control-allow-methods'),
        accessControlAllowHeaders: response.headers.get('access-control-allow-headers'),
        accessControlExposeHeaders: response.headers.get('access-control-expose-headers'),
        vary: response.headers.get('vary')
      };
    } catch (error) {
      probeErrors.push({ url, origin, method, error: error instanceof Error ? error.message : String(error) });
      return null;
    } finally {
      clearTimeout(timer);
    }
  }
  if (probeResults.length === 0) {
    const collected = [];
    for (const url of targets) {
      for (const origin of origins) {
        for (const method of ['GET', 'OPTIONS']) {
          const result = await fetchProbe(url, origin, method);
          if (result) collected.push(result);
        }
      }
    }
    probeResults = collected;
  }
  const sensitiveHeaderPattern = /authorization|cookie|token|secret|api[-_]?key|session|csrf/i;
  const scoreProbe = (probe) => {
    const allowOrigin = String(probe?.accessControlAllowOrigin || '').trim();
    const allowCredentials = /^true$/i.test(String(probe?.accessControlAllowCredentials || '').trim());
    const allowMethods = String(probe?.accessControlAllowMethods || '');
    const allowHeaders = String(probe?.accessControlAllowHeaders || '');
    const exposedHeaders = String(probe?.accessControlExposeHeaders || probe?.exposedHeaders || '');
    const origin = String(probe?.origin || '').trim();
    const reflectedOrigin = allowOrigin.toLowerCase() === origin.toLowerCase() && origin.length > 0;
    const wildcardOrigin = allowOrigin === '*';
    const nullOrigin = allowOrigin.toLowerCase() === 'null';
    const broadMethods = /\b(PUT|PATCH|DELETE|POST)\b/i.test(allowMethods);
    const authHeadersAllowed = /authorization|cookie|x-api-key|content-type/i.test(allowHeaders);
    const sensitiveHeadersExposed = sensitiveHeaderPattern.test(exposedHeaders);
    let priorityScore = 0;
    const reasons = [];
    if (reflectedOrigin) { priorityScore += 45; reasons.push('reflects arbitrary Origin'); }
    if (allowCredentials && reflectedOrigin) { priorityScore += 40; reasons.push('allows credentials for reflected Origin'); }
    if (wildcardOrigin) { priorityScore += 20; reasons.push('wildcard Access-Control-Allow-Origin'); }
    if (nullOrigin) { priorityScore += 30; reasons.push('allows null Origin'); }
    if (broadMethods) { priorityScore += 10; reasons.push('preflight allows state-changing methods'); }
    if (authHeadersAllowed) { priorityScore += 10; reasons.push('preflight allows auth/content headers'); }
    if (sensitiveHeadersExposed) { priorityScore += 10; reasons.push('exposes sensitive-looking headers'); }
    const severity = priorityScore >= 85 ? 'critical' : priorityScore >= 70 ? 'high' : priorityScore >= 40 ? 'medium' : priorityScore >= 20 ? 'low' : 'info';
    return { priorityScore, severity, reasons, reflectedOrigin, wildcardOrigin, nullOrigin, allowCredentials };
  };
  const findings = probeResults.map((probe) => {
    const scored = scoreProbe(probe);
    return {
      url: probe?.url || '',
      origin: probe?.origin || null,
      method: probe?.method || null,
      status: probe?.status ?? null,
      severity: scored.severity,
      priorityScore: scored.priorityScore,
      priorityReasons: scored.reasons,
      evidence: {
        accessControlAllowOrigin: probe?.accessControlAllowOrigin || null,
        accessControlAllowCredentials: probe?.accessControlAllowCredentials || null,
        accessControlAllowMethods: probe?.accessControlAllowMethods || null,
        accessControlAllowHeaders: probe?.accessControlAllowHeaders || null,
        accessControlExposeHeaders: probe?.accessControlExposeHeaders || probe?.exposedHeaders || null,
        vary: probe?.vary || null,
        reflectedOrigin: scored.reflectedOrigin,
        wildcardOrigin: scored.wildcardOrigin,
        nullOrigin: scored.nullOrigin,
        allowCredentials: scored.allowCredentials
      }
    };
  }).filter((finding) => finding.priorityScore >= 20).sort((a, b) => b.priorityScore - a.priorityScore || String(a.url).localeCompare(String(b.url))).slice(0, 100);
  const dangerousFindings = findings.filter((finding) => finding.evidence.reflectedOrigin && finding.evidence.allowCredentials).length;
  const highRiskCorsFindings = findings.filter((finding) => ['critical', 'high'].includes(finding.severity)).length;
  return {
    report: {
      summary: {
        targetsChecked: targets.length,
        originsTested: origins.length,
        probesAttempted: probeResults.length + probeErrors.length,
        probesSucceeded: probeResults.length,
        probeErrors: probeErrors.length,
        findings: findings.length,
        highRiskCorsFindings,
        dangerousFindings,
        topFinding: findings[0]?.url || null
      },
      authorizationNotes: typeof input.authorizationNotes === 'string' && input.authorizationNotes.trim().length > 0 ? input.authorizationNotes.trim() : null,
      targets,
      origins,
      httpBaseline: httpResponses.slice(0, 50).map((item) => ({ url: item?.url || item?.finalUrl || item?.input || null, statusCode: item?.statusCode ?? null, title: item?.title || null, technologies: Array.isArray(item?.technologies) ? item.technologies : [] })),
      findings,
      probeErrors,
      nextSteps: ['Manually verify high-risk reflected-Origin plus credentials cases with a same browser model', 'Confirm affected endpoints expose sensitive authenticated data before submitting', 'Keep follow-up requests non-destructive and inside authorized scope']
    }
  };
}
